function renderTestGate(type, message = "") {
  const isParent = type === "parent";
  const title = isParent ? "학부모 유형검사" : "중·고등 직업가치관·진로성숙도 검사";
  const subtitle = isParent ? "검사쿠폰을 입력하면 학부모 유형검사를 홈페이지 안에서 바로 진행합니다." : "검사권을 입력하면 직업가치관과 진로성숙도 검사를 홈페이지 안에서 바로 진행합니다.";
  const params = appPath().params;
  const presetCode = params.get("code") || "";
  const presetPw = params.get("pw") || "";
  const body = renderRealPageHead(title, ["검사센터", title]) + '<main class="subpage-wrap"><section class="test-page"><div class="test-card test-entry-card"><div><span class="test-hub-badge ' + (isParent ? "parent" : "") + '">' + h(isParent ? "학부모용" : "학생용") + '</span><h2>' + h(title) + '</h2><p>' + h(subtitle) + '</p></div><form id="testGateForm" class="test-form-grid"><label>검사권 번호<input name="code" required value="' + h(presetCode) + '" placeholder="' + h(isParent ? "PT-2026-ABC123" : "ST-2026-ABC123") + '"></label><label>비밀번호<input name="password" type="password" required value="' + h(presetPw) + '" placeholder="발행 시 설정한 비밀번호"></label><button class="btn" type="submit">검사 시작 / 결과 확인</button></form>' + (message ? '<p class="message error">' + h(message) + '</p>' : '') + '<div class="test-small-actions"><a class="btn ghost" href="#/tests">검사 신청 및 안내</a>' + (currentUser() ? '<a class="btn ghost" href="#/admin">검사 관리</a>' : '<a class="btn ghost" href="#/admin">관리자 로그인</a>') + '</div></div></section></main>';
  shell(title, body);
  document.getElementById("testGateForm")?.addEventListener("submit", async (event) => {
    event.preventDefault();
    const values = getFormDataObject(event.currentTarget);
    if (EDGE_ENABLED) {
      try {
        const data = await callEdge("lookupTestTicket", { code: values.code, password: values.password, type });
        cacheTestData(data);
        if (data.result) return renderTestResultPage(data.result.id);
        if (data.ticket) return type === "parent" ? renderParentExam(data.ticket) : renderStudentExam(data.ticket);
      } catch (error) {
        return renderTestGate(type, error.message || "검사권 번호 또는 비밀번호가 일치하지 않습니다.");
      }
    }
    const ticket = findTestTicket(values.code, values.password, type);
    if (!ticket) return renderTestGate(type, "검사권 번호 또는 비밀번호가 일치하지 않습니다.");
    if (ticket.resultId) return renderTestResultPage(ticket.resultId);
    if (type === "parent") return renderParentExam(ticket);
    return renderStudentExam(ticket);
  });
}
