async function submitStudentExam(ticket, form) {
  const values = getFormDataObject(form);
  const valueTotals = Object.fromEntries(STUDENT_VALUE_DEFS.map((item) => [item[0], { total: 0, count: 0 }]));
  const maturityTotals = Object.fromEntries(Object.keys(STUDENT_MATURITY_DESC).map((key) => [key, { total: 0, count: 0 }]));
  STUDENT_VALUE_ITEMS.forEach((q) => { valueTotals[q.category].total += Number(values[q.id] || 0); valueTotals[q.category].count += 1; });
  STUDENT_MATURITY_ITEMS.forEach((q) => { maturityTotals[q.category].total += Number(values[q.id] || 0); maturityTotals[q.category].count += 1; });
  const valueScores = Object.fromEntries(Object.entries(valueTotals).map(([key, item]) => [key, averageTo100(item.total, item.count)]));
  const maturityScores = Object.fromEntries(Object.entries(maturityTotals).map(([key, item]) => [key, averageTo100(item.total, item.count)]));
  const topValues = Object.entries(valueScores).sort((a, b) => b[1] - a[1]).slice(0, 3).map(([key]) => key);
  const orientationScores = Object.fromEntries(Object.entries(STUDENT_VALUE_GROUPS).map(([group, names]) => [group, Math.round(names.reduce((sum, name) => sum + (valueScores[name] || 0), 0) / names.length)]));
  const topOrientation = Object.entries(orientationScores).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
  const maturityAvg = Math.round(Object.values(maturityScores).reduce((sum, value) => sum + value, 0) / Object.values(maturityScores).length);
  let result = { id: uuid(), type: "student", ticketId: ticket.id, ticketCode: ticket.code, createdAt: new Date().toISOString(), studentName: values.studentName, school: values.school, grade: values.grade, schoolLevel: values.schoolLevel, valueScores, maturityScores, topValues, orientationScores, topOrientation, maturityAvg };
  if (EDGE_ENABLED) {
    try {
      const data = await callEdge("submitTestResult", { ticketId: ticket.id, code: ticket.code, type: "student", result });
      cacheTestData(data);
      result = data.result || result;
      return renderTestResultPage(result.id);
    } catch (error) {
      alert(error.message || "검사 결과 저장에 실패했습니다.");
      return;
    }
  }
  const results = loadTestResults();
  results.unshift(result); saveTestResults(results, { skipRemote: true });
  const tickets = loadTestTickets().map((item) => item.id === ticket.id ? { ...item, resultId: result.id, status: "완료", completedAt: result.createdAt, name: result.studentName, school: result.school, grade: result.grade, schoolLevel: result.schoolLevel } : item);
  saveTestTickets(tickets, { skipRemote: true });
  renderTestResultPage(result.id);
}
