  document.getElementById("adminPanel").innerHTML = '<div class="admin-card"><div class="program-editor-top"><div><h2>검사센터 관리</h2><p class="admin-help">검사 안내문, 신청 안내, 결과 안내 문구를 관리자 페이지에서 직접 수정할 수 있습니다. 자동 문자 발송은 별도 SMS API 연동이 필요하므로 현재 버전은 이메일 작성창 열기와 문자 문안 복사 방식으로 구현했습니다.</p></div><div class="static-mini-actions"><a class="btn" href="#/tests">검사 신청 및 안내 보기</a><a class="btn secondary" href="#/tests/student">중·고등 검사 화면</a><a class="btn secondary" href="#/tests/parent">학부모 검사 화면</a></div></div></div><div class="admin-card"><h2>검사 신청 및 안내문 수정</h2><div class="test-content-editor"><label>검사센터 제목<input data-test-content="title" value="' + h(cfg.title) + '"></label><label>안내 제목<input data-test-content="introTitle" value="' + h(cfg.introTitle) + '"></label><label class="full">검사 안내 HTML<textarea data-test-content="introHtml">' + h(cfg.introHtml) + '</textarea></label><label>신청 영역 제목<input data-test-content="requestTitle" value="' + h(cfg.requestTitle) + '"></label><label class="full">신청 도움말<textarea data-test-content="requestHelp">' + h(cfg.requestHelp) + '</textarea></label><label>결과 안내 제목<input data-test-content="resultGuideTitle" value="' + h(cfg.resultGuideTitle) + '"></label><label class="full">결과/컨설팅 안내 HTML<textarea data-test-content="resultGuideHtml">' + h(cfg.resultGuideHtml) + '</textarea></label><label class="full">학생검사 소개 문구<textarea data-test-content="studentGuide">' + h(cfg.studentGuide) + '</textarea></label><label class="full">학부모검사 소개 문구<textarea data-test-content="parentGuide">' + h(cfg.parentGuide) + '</textarea></label><label class="full">이메일 제목<input data-test-content="emailSubject" value="' + h(cfg.emailSubject) + '"></label><label class="full">이메일 안내문 템플릿<textarea data-test-content="emailTemplate">' + h(cfg.emailTemplate) + '</textarea></label><label class="full">문자 안내문 템플릿<textarea data-test-content="smsTemplate">' + h(cfg.smsTemplate) + '</textarea></label></div><p class="admin-help">사용 가능한 치환값: {검사명}, {검사권}, {비밀번호}, {검사링크}, {이름}, {학교}, {학년}</p><button class="btn" type="button" data-save-test-content>검사센터 내용 저장</button></div><div class="admin-card"><div class="program-editor-top"><div><h2>검사 신청 접수</h2><p class="admin-help">신청자 정보를 확인하고 바로 검사권을 발행할 수 있습니다. 검사권 발행 후 이메일 열기 또는 문자문안 복사를 눌러 안내하세요.</p></div><button class="btn secondary" type="button" data-export-test-requests>신청 CSV</button></div><div class="table-wrap"><table class="admin-table"><thead><tr><th>순서</th><th>상태</th><th>검사</th><th>신청자</th><th>연락처/이메일</th><th>남긴 말</th><th>검사권</th><th>관리</th></tr></thead><tbody>' + requestRows + '</tbody></table></div></div><div class="test-admin-grid"><section class="admin-card"><h2>학생 검사권 수동 발행</h2><form id="issueStudentTest" class="test-admin-form"><label>학생명<input name="name" placeholder="홍길동"></label><label>소속/그룹<input name="group" placeholder="정관고 2학년"></label><label>연락처<input name="phone" placeholder="010-0000-0000"></label><label>이메일<input name="email" type="email" placeholder="example@email.com"></label><label>학교급<select name="schoolLevel"><option value="middle">중등</option><option value="high">고등</option></select></label><label>발행 수<input name="quantity" type="number" min="1" max="200" value="1"></label><label>공통 비밀번호<input name="password" placeholder="미입력 시 자동 생성"></label><button class="btn" type="submit">학생 검사권 발행</button></form></section><section class="admin-card"><h2>학부모 검사쿠폰 수동 발행</h2><form id="issueParentTest" class="test-admin-form"><label>보호자명<input name="name" placeholder="보호자"></label><label>소속/그룹<input name="group" placeholder="학부모교실 1기"></label><label>연락처<input name="phone" placeholder="010-0000-0000"></label><label>이메일<input name="email" type="email" placeholder="example@email.com"></label><label>발행 수<input name="quantity" type="number" min="1" max="200" value="1"></label><label>공통 비밀번호<input name="password" placeholder="미입력 시 자동 생성"></label><button class="btn secondary" type="submit">학부모 검사쿠폰 발행</button></form></section></div><div class="admin-card"><div class="program-editor-top"><div><h2>검사권 목록</h2><p class="admin-help">쿠폰번호와 비밀번호를 응시자에게 안내하세요. 완료된 검사권은 결과 버튼으로 출력할 수 있습니다.</p></div><div class="static-mini-actions"><button class="btn secondary" type="button" data-export-tests="tickets">검사권 CSV</button><button class="btn secondary" type="button" data-export-tests="results">결과 CSV</button></div></div><div class="table-wrap"><table class="admin-table"><thead><tr><th>순서</th><th>검사권</th><th>검사</th><th>대상/그룹</th><th>연락처/이메일</th><th>상태</th><th>발행일</th><th>관리</th></tr></thead><tbody>' + ticketRows + '</tbody></table></div></div><div class="admin-card"><h2>검사 결과</h2><div class="table-wrap"><table class="admin-table"><thead><tr><th>순서</th><th>검사</th><th>이름</th><th>소속/자녀</th><th>핵심 결과</th><th>완료일</th><th>관리</th></tr></thead><tbody>' + resultRows + '</tbody></table></div></div>';
  document.getElementById("issueStudentTest")?.addEventListener("submit", (event) => { event.preventDefault(); issueTestTickets("student", event.currentTarget); });
  document.getElementById("issueParentTest")?.addEventListener("submit", (event) => { event.preventDefault(); issueTestTickets("parent", event.currentTarget); });
  document.querySelector("[data-save-test-content]")?.addEventListener("click", saveTestCenterContent);
