function renderConsulting() {
  const c = site.consulting || {};
  const program = programForWritePath("/04sub01/write");
  shell("1:1맞춤형컨설팅", renderRealPageHead("1:1맞춤형컨설팅", ["프로그램 참가신청", "1:1 맞춤형 컨설팅"]) + '<main class="real-consult-page"><section class="real-consult-intro"><div class="real-consult-title"><span></span><h2>' + h(c.pageTitle || "1:1진학상담") + '</h2></div><div class="real-consult-notice"><h3>' + h(c.noticeTitle || "") + '</h3><p class="real-consult-alert">' + h(c.noticeSubtitle || "") + '</p><div class="real-consult-box">' + safeHtml(c.noticeHtml || "") + '</div></div></section><nav class="real-consult-actions ' + (currentUser() ? "show-authed-items" : "") + '" aria-label="1:1 맞춤형 컨설팅 신청 메뉴"><a class="apply" href="' + routeHref(program.writePath || "/04sub01/write") + '">신청하기</a><a class="lookup" href="#/content/컨설턴트-신청확인/">신청조회</a>' + (currentUser() ? '<a class="confirm" href="#/04sub01">신청확인</a>' : "") + '</nav></main>');
}

function renderWriteForm(page = null) {
  const form = site.form || {};
  const labels = formLabels();
  const req = (key, fallback) => h(labels[key] || fallback || key) + ' <span class="required">*</span>';
  const residences = Array.isArray(form.residences) ? form.residences : [];
  const programConfig = programForWritePath(appPath().pathname, page);
  const pageTitle = programConfig.title || page?.title || "1:1 맞춤형 컨설팅";
  const schedules = activeProgramSchedules(programConfig).sort((a, b) => String(a.date + " " + ((a.times || [])[0] || "")).localeCompare(String(b.date + " " + ((b.times || [])[0] || ""))));
  const scheduleNotice = schedules.length ? "" : '<div class="message error full">' + h(labels.noScheduleMessage || "관리자가 열어둔 신청 가능 일정이 없습니다.") + '</div>';
  const submitDisabled = schedules.length ? "" : " disabled";
  const firstDate = schedules[0]?.date || new Date().toISOString().slice(0, 10);
  const [initialYear, initialMonth] = firstDate.split("-").map(Number);
  const scheduleIntro = schedules.length ? '<div class="consult-calendar-helper">' + h(labels.calendarHelp || "달력에서 상담 가능 날짜를 선택하면 오른쪽에 장소와 담당 컨설턴트가 표시됩니다. 일정을 선택한 뒤 시간을 골라주세요.") + '</div>' : "";
  const defaultContent = programConfig.defaultContent || form.defaultContent || "";
  const body = renderRealPageHead(pageTitle, ["프로그램 참가신청"]) +
    '<section class="form-card consult-apply-card"><h1 class="form-title">' + h(pageTitle) + ' 신청합니다</h1>' +
    '<form id="applyForm">' +
    '<input type="hidden" name="programId" value="' + h(programConfig.id) + '">' +
    '<input type="hidden" name="programTitle" value="' + h(pageTitle) + '">' +
    '<input type="hidden" name="programPath" value="' + h(programConfig.path || page?.path || "/content/11맞춤형컨설팅/") + '">' +
    '<input type="hidden" name="scheduleId" id="scheduleId"><input type="hidden" name="consultantId" id="consultantId"><input type="hidden" name="consultantName" id="consultantName"><input type="hidden" name="place" id="place"><input type="hidden" name="date" id="date">' +
    '<div class="agree-box"><h2>' + h(labels.privacyTitle || "개인정보 수집 및 이용에 대한 동의") + '</h2><textarea readonly>' + h(labels.privacyText || "상담 운영과 신청 확인을 위해 입력 정보를 저장합니다.") + '</textarea><label><input type="checkbox" name="agree" value="1" required> ' + h(labels.privacyAgree || "예") + '</label></div>' +
    '<div class="form-grid">' + scheduleNotice +
    '<div class="form-field full"><span class="field-label">' + req("applicantType", "신청자") + '</span><div class="radio-row"><label class="radio-pill"><input type="radio" name="applicantType" value="학부모" required><span>학부모</span></label><label class="radio-pill"><input type="radio" name="applicantType" value="학생" required><span>학생</span></label></div></div>' +
    '<div class="form-field full"><label>' + req("schedule", "상담 일정") + '</label>' + scheduleIntro + '<div class="consult-calendar-layout" data-consult-calendar><section class="consult-calendar-card"><div class="consult-calendar-head"><button type="button" class="consult-cal-nav" data-consult-prev aria-label="이전 달">‹</button><strong id="consultCalendarTitle"></strong><button type="button" class="consult-cal-nav" data-consult-next aria-label="다음 달">›</button></div><div class="consult-week-row"><span>일</span><span>월</span><span>화</span><span>수</span><span>목</span><span>금</span><span>토</span></div><div class="consult-date-grid" id="consultDateGrid"></div></section><section class="consult-day-panel"><div class="consult-day-head"><span class="consult-day-label">선택한 날짜</span><strong id="consultSelectedDate">날짜를 선택해주세요</strong></div><div class="consult-day-list" id="consultDayList"></div></section></div><div class="schedule-summary" id="scheduleSummary">상담 가능 날짜를 선택해주세요.</div></div>' +
    '<div class="form-field full"><span class="field-label">' + req("selectedTime", "선택시간") + '</span><div class="time-row consult-time-row" id="timeOptions"><p class="message">날짜와 일정을 먼저 선택해주세요.</p></div></div>' +
    '<div class="form-field"><label>' + req("residence", "거주지") + '</label><select name="residence" required><option value="">' + h(labels.residencePlaceholder || "선택하세요") + '</option>' + residences.map((item) => '<option value="' + h(item) + '">' + h(item) + '</option>').join("") + '</select></div>' +
    '<div class="form-field"><label>' + req("studentName", "이름") + '</label><input name="studentName" required></div>' +
    '<div class="form-field"><label>' + req("parentPhone", "학부모 연락처") + '</label><input name="parentPhone" required placeholder="010-0000-0000"></div>' +
    '<div class="form-field"><label>' + req("studentPhone", "학생 연락처") + '</label><input name="studentPhone" required placeholder="010-0000-0000"></div>' +
    '<div class="form-field"><label>' + req("school", "학교명") + '</label><input name="school" required></div>' +
    '<div class="form-field"><label>' + req("grade", "학년") + '</label><input name="grade" required></div>' +
    '<div class="form-field"><label>' + req("password", "비밀번호") + '</label><input name="password" type="password" required></div>' +
    '<div class="form-field full"><label>' + req("content", "상담 희망 내용") + '</label><textarea name="content" required>' + h(defaultContent) + '</textarea></div>' +
    '</div><div class="message" id="applyMessage"></div><button type="submit" class="btn"' + submitDisabled + '>신청하기</button></form></section>';
  shell(pageTitle + " 신청", body);
  const formElement = document.getElementById("applyForm");
  const scheduleIdInput = document.getElementById("scheduleId");
  const calendarTitle = document.getElementById("consultCalendarTitle");
  const dateGrid = document.getElementById("consultDateGrid");
  const selectedDateEl = document.getElementById("consultSelectedDate");
  const dayListEl = document.getElementById("consultDayList");
  const timeOptionsEl = document.getElementById("timeOptions");
  let currentYear = Number(initialYear) || new Date().getFullYear();
  let currentMonth = Number.isFinite(initialMonth) ? (initialMonth - 1) : new Date().getMonth();
  let selectedDate = "";
  let selectedScheduleId = "";
  const scheduleDates = new Set(schedules.map((schedule) => schedule.date));
  const schedulesForDate = (date) => schedules.filter((schedule) => schedule.date === date);
  const scheduleById = (id) => schedules.find((schedule) => schedule.id === id);
  const setHiddenSchedule = (schedule) => {
    const name = schedule ? consultantName(schedule.consultantId) : "";
    scheduleIdInput.value = schedule?.id || "";
    document.getElementById("consultantId").value = schedule?.consultantId || "";
    document.getElementById("consultantName").value = name;
    document.getElementById("place").value = schedule?.place || "";
    document.getElementById("date").value = schedule?.date || "";
  };
  const clearTimes = (message = "날짜와 일정을 먼저 선택해주세요.") => {
    timeOptionsEl.innerHTML = '<p class="message">' + h(message) + '</p>';
  };
  const renderTimes = (schedule) => {
    setHiddenSchedule(schedule);
    if (!schedule) {
      document.getElementById("scheduleSummary").textContent = "상담 가능 날짜를 선택해주세요.";
      clearTimes();
      return;
    }
    const name = consultantName(schedule.consultantId);
    document.getElementById("scheduleSummary").innerHTML = '<strong>' + h(schedule.date) + '</strong> / ' + h(name) + ' / ' + h(schedule.place);
    const availableTimes = (schedule.times || []).map((time) => {
      const booked = applications.some((item) => item.status !== "취소" && item.consultantId === schedule.consultantId && item.date === schedule.date && item.time === time);
      return '<label class="radio-pill ' + (booked ? "disabled" : "") + '"><input type="radio" name="time" value="' + h(time) + '" required ' + (booked ? "disabled" : "") + '><span>' + h(time) + (booked ? " 마감" : "") + '</span></label>';
    }).join("");
    timeOptionsEl.innerHTML = availableTimes || '<p class="message error">선택 가능한 시간이 없습니다.</p>';
  };
  const renderDayList = () => {
    selectedDateEl.textContent = selectedDate || "날짜를 선택해주세요";
    const daySchedules = schedulesForDate(selectedDate);
    if (!selectedDate) {
      dayListEl.innerHTML = '<p class="consult-empty-text">달력에서 표시된 날짜를 선택해주세요.</p>';
      selectedScheduleId = "";
      setHiddenSchedule(null);
      clearTimes();
      return;
    }
    if (!daySchedules.length) {
      dayListEl.innerHTML = '<p class="consult-empty-text">이 날짜에는 신청 가능한 일정이 없습니다.</p>';
      selectedScheduleId = "";
      setHiddenSchedule(null);
      clearTimes("신청 가능한 일정이 있는 날짜를 선택해주세요.");
      return;
    }
    if (!selectedScheduleId || !daySchedules.some((schedule) => schedule.id === selectedScheduleId)) selectedScheduleId = daySchedules[0].id;
    dayListEl.innerHTML = daySchedules.map((schedule) => {
      const bookedCount = (schedule.times || []).filter((time) => applications.some((item) => item.status !== "취소" && item.consultantId === schedule.consultantId && item.date === schedule.date && item.time === time)).length;
      const totalCount = (schedule.times || []).length;
      const leftCount = Math.max(0, totalCount - bookedCount);
      return '<button type="button" class="consult-schedule-item ' + (schedule.id === selectedScheduleId ? "active" : "") + '" data-schedule-pick="' + h(schedule.id) + '"><strong>' + h(consultantName(schedule.consultantId) || "담당자") + '</strong><span>' + h(schedule.place || "장소 미정") + '</span><em>' + h((schedule.times || []).join(", ")) + '</em><small>예약 가능 ' + leftCount + ' / ' + totalCount + '</small></button>';
    }).join("");
    renderTimes(scheduleById(selectedScheduleId));
    dayListEl.querySelectorAll("[data-schedule-pick]").forEach((button) => button.addEventListener("click", () => {
      selectedScheduleId = button.dataset.schedulePick;
      renderDayList();
    }));
  };
  const renderCalendar = () => {
    if (!dateGrid) return;
    calendarTitle.textContent = currentYear + "." + String(currentMonth + 1).padStart(2, "0");
    const first = new Date(currentYear, currentMonth, 1);
    const last = new Date(currentYear, currentMonth + 1, 0);
    const cells = [];
    for (let i = 0; i < first.getDay(); i += 1) cells.push({ blank: true });
    for (let day = 1; day <= last.getDate(); day += 1) {
      const iso = currentYear + "-" + String(currentMonth + 1).padStart(2, "0") + "-" + String(day).padStart(2, "0");
      cells.push({ day, iso, enabled: scheduleDates.has(iso) });
    }
    dateGrid.innerHTML = cells.map((cell) => cell.blank ? '<span class="consult-date-cell blank"></span>' : '<button type="button" class="consult-date-cell ' + (cell.enabled ? "has-schedule" : "") + (cell.iso === selectedDate ? " selected" : "") + '" data-date="' + h(cell.iso) + '" ' + (cell.enabled ? "" : "disabled") + '><span>' + cell.day + '</span>' + (cell.enabled ? '<i></i>' : '') + '</button>').join("");
    dateGrid.querySelectorAll("[data-date]").forEach((button) => button.addEventListener("click", () => {
      if (!scheduleDates.has(button.dataset.date)) return;
      selectedDate = button.dataset.date;
      selectedScheduleId = "";
      renderCalendar();
      renderDayList();
    }));
  };
  document.querySelector("[data-consult-prev]")?.addEventListener("click", () => {
    currentMonth -= 1;
    if (currentMonth < 0) { currentMonth = 11; currentYear -= 1; }
    renderCalendar();
  });
  document.querySelector("[data-consult-next]")?.addEventListener("click", () => {
    currentMonth += 1;
    if (currentMonth > 11) { currentMonth = 0; currentYear += 1; }
    renderCalendar();
  });
  renderCalendar();
  if (schedules.length) {
    selectedDate = firstDate;
    renderCalendar();
    renderDayList();
  } else {
    renderDayList();
  }
  formElement.addEventListener("submit", async (event) => {
    event.preventDefault();
    const data = Object.fromEntries(new FormData(event.currentTarget).entries());
    const schedule = schedules.find((item) => item.id === data.scheduleId);
    if (!schedule || !schedule.times.includes(data.time)) {
      document.getElementById("applyMessage").className = "message error";
      document.getElementById("applyMessage").textContent = "신청 가능한 일정과 시간을 다시 선택해주세요.";
      return;
    }
    data.programId = programConfig.id;
    data.programTitle = pageTitle;
    data.programPath = programConfig.path || page?.path || "/content/11맞춤형컨설팅/";
    data.consultantId = schedule.consultantId;
    data.consultantName = consultantName(schedule.consultantId);
    data.place = schedule.place;
    data.date = schedule.date;
    if (EDGE_ENABLED) {
      try {
        const result = await callEdge("submitApplication", { application: data });
        applications.unshift(result.application);
        saveJson(KEY_APPLICATIONS, applications);
        setRoute("/04sub01?submitted=1");
      } catch (error) {
        document.getElementById("applyMessage").className = "message error";
        document.getElementById("applyMessage").textContent = error.message || "신청 접수에 실패했습니다.";
      }
      return;
    }
    try {
      await refreshApplicationsFromRemote();
    } catch (error) {
      document.getElementById("applyMessage").className = "message error";
      document.getElementById("applyMessage").textContent = "신청 목록을 확인하지 못했습니다. 잠시 후 다시 시도해주세요.";
      return;
    }
    const duplicate = applications.find((item) => item.status !== "취소" && item.consultantId === data.consultantId && item.date === data.date && item.time === data.time);
    if (duplicate) {
      document.getElementById("applyMessage").className = "message error";
      document.getElementById("applyMessage").textContent = "이미 같은 컨설턴트의 같은 날짜와 시간에 접수된 신청이 있습니다. 다른 시간을 선택해주세요.";
      renderDayList();
      return;
    }
    applications.unshift({ id: uuid(), createdAt: new Date().toISOString(), status: "접수", memo: "", ...data });
    saveApplications();
    setRoute("/04sub01?submitted=1");
  });
}

function renderConfirmList(submitted = false, loaded = false) {
  if (!currentUser()) {
    if (submitted) return shell("상담 신청 접수완료", renderRealPageHead("1:1맞춤형컨설팅") + '<main class="real-confirm-page"><div class="confirm-success">상담 신청이 접수되었습니다.</div><div class="submitted-actions"><a class="real-outline-button" href="#/content/컨설턴트-신청확인/">신청조회</a><a class="real-outline-button" href="#/content/11맞춤형컨설팅/">상담 안내로 이동</a></div></main>');
    return renderLogin();
  }
  if (EDGE_ENABLED && !loaded) {
    shell("1:1맞춤형컨설팅 신청확인", renderRealPageHead("1:1맞춤형컨설팅") + '<main class="real-confirm-page"><div class="confirm-success">신청 내역을 불러오는 중입니다.</div></main>');
    refreshApplicationsFromRemote().then(() => renderConfirmList(submitted, true)).catch((error) => {
      shell("1:1맞춤형컨설팅 신청확인", renderRealPageHead("1:1맞춤형컨설팅") + '<main class="real-confirm-page"><div class="message error">' + h(error.message || "신청 내역을 불러오지 못했습니다.") + '</div></main>');
    });
    return;
  }
  const list = applicationsForCurrentUser();
  const total = list.length;
  const rows = list.length ? list.map((item, index) => '<tr><td>' + (total - index) + '</td><td>' + h(item.programTitle || "상담 신청") + '</td><td class="consultant">' + h(item.consultantName) + '</td><td>' + h(compactDateTime(item.date, item.time)) + '</td><td>' + h(item.school) + '</td><td>' + h(item.grade) + '</td><td>' + h(item.studentName) + '</td><td>' + h(item.applicantType) + '</td><td>' + h(item.viewCount || "") + '</td><td>' + h(shortDate(item.createdAt)) + '</td><td>' + h(item.status || "접수") + '</td></tr>').join("") : '<tr><td class="empty" colspan="11">등록된 신청 내역이 없습니다.</td></tr>';
  shell("1:1맞춤형컨설팅 신청확인", renderRealPageHead("1:1맞춤형컨설팅") + '<main class="real-confirm-page">' + (submitted ? '<div class="confirm-success">상담 신청이 접수되었습니다.</div>' : "") + '<div class="real-confirm-toolbar"><p>TOTAL ' + total + '건 1 페이지</p><div><button class="real-outline-button" type="button" data-export>⊙ 엑셀 다운로드</button></div></div><div class="real-confirm-table-wrap"><table class="real-confirm-table"><thead><tr><th>번호</th><th>프로그램</th><th>컨설턴트</th><th>날짜/시간</th><th>학교</th><th>학년</th><th>학생이름</th><th>신청자</th><th>조회</th><th>신청일</th><th>상태</th></tr></thead><tbody>' + rows + '</tbody></table></div></main>');
  document.querySelector("[data-export]")?.addEventListener("click", exportApplications);
}

function renderLookup() {
  shell("신청조회", renderRealPageHead("컨설턴트 신청확인", ["프로그램 참가신청"]) + '<main class="subpage-wrap"><section class="lookup-card"><h1>신청조회</h1><div class="form-grid"><div class="form-field"><label>이름</label><input id="lookupName"></div><div class="form-field"><label>비밀번호</label><input id="lookupPassword" type="password"></div></div><button class="btn" id="lookupButton">조회</button><div class="message" id="lookupMessage"></div><div class="result-list" id="lookupResult"></div></section></main>');
  document.getElementById("lookupButton").addEventListener("click", async () => {
    const name = document.getElementById("lookupName").value.trim();
    const password = document.getElementById("lookupPassword").value;
    let result = [];
    if (EDGE_ENABLED) {
      try {
        const response = await callEdge("lookupApplication", { name, password });
        result = response.applications || [];
      } catch (error) {
        document.getElementById("lookupMessage").className = "message error";
        document.getElementById("lookupMessage").textContent = error.message || "신청 내역을 조회하지 못했습니다.";
        return;
      }
    } else {
      result = applications.filter((item) => item.studentName === name && item.password === password);
    }
    document.getElementById("lookupMessage").className = "message";
    document.getElementById("lookupMessage").textContent = result.length ? result.length + "건의 신청 내역이 있습니다." : "일치하는 신청 내역이 없습니다.";
    document.getElementById("lookupResult").innerHTML = result.map((item) => '<div class="result-item"><strong>' + h(item.status) + '</strong><p>' + h(item.programTitle || "상담 신청") + '</p><p>' + h(item.consultantName) + ' / ' + h(item.place) + '</p><p>' + h(item.date) + ' ' + h(item.time) + '</p><p>' + h(item.school) + ' ' + h(item.grade) + '</p></div>').join("");
  });
}

function renderSchedule(date = "") {
  const map = eventsByDate();
  const active = date || [...map.keys()][0] || "2026-06-01";
  const events = map.get(active) || [];
  const rows = events.map((event) => {
    if (event.type === "reservation") return '<div class="schedule-event-link reservation-event"><strong>' + h(event.title) + '</strong><span>' + h([event.time, event.place, event.status].filter(Boolean).join(" / ")) + '</span></div>';
    return '<a class="schedule-event-link" href="#/05sub06/schedule/' + event.index + '"><strong>' + h(event.title) + '</strong><span>' + h(scheduleDisplayMeta(event)) + '</span></a>';
  }).join("");
  shell("센터일정", renderRealPageHead("센터일정", ["열린마당", "센터 일정"]) + '<main class="center-schedule-page"><section class="center-month-head"><strong>2026.6</strong></section><section class="center-selected-day"><div class="selected-date-card"><div class="date-card-icon">▣</div><strong>' + h(active) + '</strong></div><div>' + (rows || '<p class="message">표시할 일정이 없습니다.</p>') + '</div></section></main>');
}
function renderScheduleDetail(index) {
  const event = publicScheduleGroups()[Number(index)];
  if (!event) return renderNotFound();
  const body = '<p><strong>프로그램</strong>: ' + h(event.programTitle || "상담") + '</p><p><strong>날짜</strong>: ' + h(event.date) + '</p><p><strong>시간</strong>: ' + h((event.times || []).join(", ")) + '</p><p><strong>컨설턴트</strong>: ' + h(event.consultantName || consultantName(event.consultantId)) + '</p><p><strong>장소</strong>: ' + h(event.place || "") + '</p>';
  shell("센터일정", renderRealPageHead("센터일정", ["열린마당", "센터 일정"]) + '<main class="center-schedule-detail-page"><div class="schedule-detail-actions"><a class="real-outline-button" href="#/05sub06?date=' + h(event.date) + '">☷ 목록</a></div><article class="schedule-detail-article"><header><h2>' + h(scheduleDisplayTitle(event)) + '</h2></header><div class="schedule-detail-body">' + body + '</div></article></main>');
}

function renderLogin() {
  shell("로그인", '<main class="login-bg"><form class="login-card" id="loginForm"><img src="' + h(site.logo) + '" alt="' + h(site.siteName) + '"><h1>로그인</h1><input name="id" placeholder="아이디" required><input name="password" type="password" placeholder="비밀번호" required><button type="submit" class="btn">LOGIN</button><p class="message error" id="loginError"></p></form></main>');
  document.getElementById("loginForm").addEventListener("submit", async (event) => {
    event.preventDefault();
    const data = Object.fromEntries(new FormData(event.currentTarget).entries());
    if (EDGE_ENABLED) {
      try {
        session = await signInWithSupabaseAuth(data.id, data.password);
        saveSession();
        setRoute("/admin");
      } catch (error) {
        document.getElementById("loginError").textContent = error.message || "아이디 또는 비밀번호를 확인해주세요.";
      }
      return;
    }
    const user = users.find((item) => item.id === data.id && item.password === data.password);
    if (!user) {
      document.getElementById("loginError").textContent = "아이디 또는 비밀번호를 확인해주세요.";
      return;
    }
    session = { id: user.id, role: user.role, name: user.name };
    saveSession();
    setRoute("/admin");
  });
}
function adminStorageNote() {
  if (!REMOTE_ENABLED) return "현재 데이터는 이 브라우저에만 저장됩니다. Supabase 설정을 넣으면 여러 컴퓨터에서 같은 데이터를 공유합니다.";
  if (remoteLoading) return "Supabase DB에서 데이터를 불러오는 중입니다.";
  if (remoteError) return "Supabase 연결 오류: " + remoteError + " 설정값과 테이블을 확인해주세요.";
  if (EDGE_ENABLED && remoteReady) return "Supabase Auth + Edge Function 보안 모드 연결됨: 관리자/컨설턴트 권한을 서버에서 확인합니다.";
  if (remoteReady) return "Supabase DB 연결됨: 신청자와 관리자 수정 내용이 연결된 DB에 저장됩니다.";
  return "Supabase 설정이 감지되었습니다. 저장 시 DB에 동기화됩니다.";
}
function renderAdmin(tab = "applications") {
  if (!currentUser()) return renderLogin();
  const adminMode = isAdmin();
  const programMode = canManagePrograms();
  const tabs = adminMode ? [["applications","상담 신청"],["programs","프로그램/일정"],["tests","검사 관리"],["content","기본 내용"],["menus","메뉴 내용"],["images","배너/이미지"],["boards","게시판"],["users","계정관리"],["password","비밀번호 변경"]] : (programMode ? [["applications","상담 신청"],["programs","프로그램/일정"],["password","비밀번호 변경"]] : [["applications","상담 신청"],["password","비밀번호 변경"]]);
  const active = tabs.some((item) => item[0] === tab) ? tab : "applications";
  const resetButton = adminMode ? '<button class="btn ghost" type="button" data-reset>초기화</button>' : "";
  shell("관리자", '<main class="admin-shell"><div class="admin-topbar"><h1>' + h(currentUser().name) + ' 관리 페이지</h1><div class="admin-actions"><a class="btn ghost" href="#/">사이트 보기</a>' + resetButton + '<a class="btn ghost" href="#/logout">로그아웃</a></div></div><p class="static-admin-note">' + h(adminStorageNote()) + '</p><div class="admin-tabs">' + tabs.map((item) => '<button class="' + (item[0] === active ? "active" : "") + '" data-admin-tab="' + item[0] + '">' + item[1] + '</button>').join("") + '</div><section id="adminPanel"></section></main>');
  document.querySelectorAll("[data-admin-tab]").forEach((button) => button.addEventListener("click", () => renderAdmin(button.dataset.adminTab)));
  document.querySelector("[data-reset]")?.addEventListener("click", () => {
    if (!confirm("현재 브라우저에 저장된 정적 HTML 데이터를 초기화할까요?")) return;
    localStorage.removeItem(KEY_SITE); localStorage.removeItem(KEY_USERS); localStorage.removeItem(KEY_APPLICATIONS); localStorage.removeItem(KEY_SESSION);
    site = clone(INITIAL_SITE); users = clone(INITIAL_USERS); applications = clone(INITIAL_APPLICATIONS); session = null;
    setRoute("/");
  });
  if (active === "applications") renderAdminApplications();
  if (active === "programs") renderAdminPrograms();
  if (active === "tests") renderAdminTests();
  if (active === "content") renderAdminContent();
  if (active === "menus") renderAdminMenus();
  if (active === "images") renderAdminImages();
  if (active === "boards") renderAdminBoards();
  if (active === "users") renderAdminUsers();
  if (active === "password") renderAdminPassword();
}
